        "lang": "text",
        "label": "Three layers and the inward dependency rule (pseudocode)",
        "code": "// ---- DOMAIN (inner, framework-FREE) --------------------------\n// Plain model: no JSON/DB annotations, no framework types\nstruct User { id, name, isPremium }\n\n// The interface the domain NEEDS -- defined HERE, in the domain\ninterface UserRepository {\n    getUser(id) -> User          // returns a DOMAIN model\n}\n\n// A use-case / interactor: one business rule, pure and testable\nclass GetDiscountEligibility(repo: UserRepository) {\n    run(id): Boolean {\n        u = repo.getUser(id)\n        return u.isPremium and accountOlderThan(u, days = 30)\n    }\n}\n\n// ---- DATA (outer) implements the domain's interface ----------\nclass UserRepositoryImpl(api, db) : UserRepository {\n    getUser(id) -> User {\n        dto = api.fetchUser(id)      // network DTO, framework-shaped\n        return dto.toDomain()        // MAP DTO -> domain model here\n    }\n}\n\n// ---- PRESENTATION (outer) depends on the domain --------------\nclass ProfileViewModel(getEligibility: GetDiscountEligibility) {\n    load(id): state = Ready(showDiscount = getEligibility.run(id))\n}\n\n// Dependencies point INWARD: presentation -> domain <- data.\n// The domain imports NOTHING outward -> portable + unit-testable."
