/** Phase 2 flashcard deck keyed by topic id. */
export const MOBILE_ARCH_FLASHCARDS: FlashcardData = {
  'architecture-patterns': [
    { id: 'mbfc_arch_1', q: 'Trace the evolution MVC -> MVP -> MVVM -> MVI and the problem each step solves.', a: "MVC splits data/view/input, but on mobile the framework's screen object is both View and Controller, so they fuse into a massive class with logic and UI entangled. MVP extracts a Presenter holding presentation logic and talks to a passive View through an interface (testable, but they reference each other, one method per change). MVVM removes the back-reference: the ViewModel just exposes observable state the View subscribes to, so logic has no UI knowledge and is trivially unit-testable. MVI enforces unidirectional flow: intents in, one immutable state from a reducer, UI renders that single state.", hint: 'Each step reduces entanglement and ways state can change.' },
    { id: 'mbfc_arch_2', q: 'Why is an MVVM ViewModel more testable than an MVC screen, and what is the one dependency rule?', a: "In MVC the presentation logic lives inside the screen class alongside framework UI types, so you cannot exercise it without real UI. MVVM moves that logic into a ViewModel holding only plain data and exposing observable state, so a unit test calls its functions and asserts on state with no device. The rule that makes it work: the View may reference the ViewModel, but the ViewModel must never reference the View or any UI type/Context. That single one-way arrow keeps logic UI-free (testable) and on Android prevents leaking the Activity across recreation." },
    { id: 'mbfc_arch_3', q: 'What does MVI unidirectional data flow buy over MVVM, and when is it not worth it?', a: "MVI makes state a single immutable value changed only by emitting an intent that a reducer turns into a new state, with the UI a pure function render(state). Over MVVM it gives one source of truth per screen, no partial or conflicting mutations from multiple paths, and reproducible/loggable state — a big win for complex screens with many interacting flags and racing async work. The cost is boilerplate (intents, reducer, state class per screen), so for simple two-field screens plain MVVM is the better fit." },
    { id: 'mbfc_arch_4', q: 'How do Android and iOS each express the MVVM/MVI idea?', a: "Android: a lifecycle-scoped ViewModel exposing observable state (StateFlow/LiveData) that the UI (Views or Compose) collects; MVI is layered on by making state a single immutable data class updated by a reducer. iOS: an ObservableObject/@Observable ViewModel with @Published state that a SwiftUI View watches via @StateObject and auto-re-renders; unidirectional frameworks like TCA are the MVI equivalent. Different observability primitives, identical goal: an observable ViewModel the UI watches, with no back-reference from logic to UI." },
    { id: 'mbfc_arch_5', q: 'What is the massive-view-controller / god-activity anti-pattern and how do you avoid it?', a: "It is a screen class that fetches data, applies business rules, formats strings, and draws UI all in one place, ballooning to thousands of lines so nothing is unit-testable and every change risks unrelated breakage. Avoid it by moving all presentation logic into a UI-agnostic ViewModel (MVVM) that exposes observable state, keeping the screen a thin renderer of that state, and never putting business rules in the View layer.", hint: 'If you cannot test the screen without a simulator, the logic is in the wrong place.' },
  ],
  'layered-clean-architecture': [
    { id: 'mbfc_arch_6', q: 'Name the three layers of Clean/layered architecture and state the dependency rule.', a: "Presentation (UI + ViewModels showing state and forwarding actions), domain (business rules and use-cases/interactors with no UI/network/DB framework references), and data (repository implementations, network clients, databases, caches). The dependency rule: dependencies point inward toward the domain — presentation depends on domain, data depends on domain, and the domain depends on nothing outward. The domain is the stable core; outer layers are replaceable details that adapt to it.", hint: 'Nothing inner may import anything outer.' },
    { id: 'mbfc_arch_7', q: 'How can the data layer depend on the domain while the domain depends on nothing outward?', a: "Through dependency inversion. The domain declares the interface it needs (e.g. UserRepository.getUser() returning a domain model) using only plain types. The data layer provides a concrete class implementing that interface, wrapping the real network/DB. So at compile time the domain has no dependency on data; it is data that depends on the domain to satisfy the contract, and the composition root supplies the implementation at runtime. The interface lives inner, the implementation outer — inverting the arrow." },
    { id: 'mbfc_arch_8', q: 'Why does keeping the domain framework-free make knowledge framework-agnostic, and what breaks if it leaks?', a: "If the domain imports a framework type (a Context, a Retrofit Response, a DB annotation), the rules are chained to that framework: you cannot compile/test them without it or move them to another platform. Keeping the domain as pure plain-language code means the 'what the app does' is expressed in terms any framework can satisfy, so the same rules work under Flutter, React Native, Kotlin, or Swift. If it leaks: testability collapses (need the framework to test logic), portability collapses (rules only run on that stack), and framework changes ripple through the core." },
    { id: 'mbfc_arch_9', q: 'What are use-cases (interactors) and why map DTOs to domain models at the boundary?', a: "Use-cases are small single-purpose objects in the domain that orchestrate one business rule — GetFeed, PlaceOrder, ApplyDiscount — each callable and testable in isolation, keeping ViewModels thin and rules out of the UI. Mapping DTOs (shaped by the API/DB) to domain models (shaped by business meaning) at the data-layer boundary means a change in the API's JSON shape does not ripple into your business rules; the core stays defined by meaning, not by an external wire format." },
    { id: 'mbfc_arch_10', q: 'How is the dependency rule enforced structurally rather than by good intentions?', a: "By the build system's module/package boundary. On Android, a pure-Kotlin :domain module with no Android dependencies literally will not compile against the Android SDK or Retrofit, so a leak is a build error, not a review nicety. On iOS, a Domain Swift package that imports no UIKit/SwiftUI does the same. The compiler becomes the wall: illegal inward dependencies simply fail to build, making the dependency rule impossible to violate by accident.", hint: 'Make the violation a compile error.' },
  ],
  'dependency-injection': [
    { id: 'mbfc_arch_11', q: 'What is Inversion of Control, how does DI implement it, and why does it make code testable/swappable?', a: "IoC means an object no longer creates and controls its own dependencies; that control is inverted so they are supplied from outside. DI implements it: a class declares what it needs and receives ready-made instances instead of constructing them with 'new', and a composition root builds the object graph and injects the pieces. This makes code testable (a test injects fakes/mocks instead of real collaborators) and swappable (substitute one implementation for another — in-memory cache for real, mock gateway for live — without changing the class).", hint: 'Declare needs; receive them from outside.' },
    { id: 'mbfc_arch_12', q: 'Compare constructor injection, field injection, and the Service Locator.', a: "Constructor injection passes deps through the constructor — the default: the object is always fully formed and its needs are explicit in the signature, maximizing testability. Field injection sets deps on fields after construction — for framework-created objects (Activities, view controllers) whose constructor you do not control, but it hides requirements and allows a half-built object. Service Locator has the class pull deps from a global registry — it also inverts creation but hides true dependencies, couples the class to the locator, and makes tests fragile. Prefer constructor injection; field injection for framework-instantiated classes; locator only as a fallback." },
    { id: 'mbfc_arch_13', q: 'What is dependency scope/lifetime and what goes wrong if you get it wrong?', a: "Scope is how long a provided instance lives and who shares it: singleton (one per app — right for stateless process-lifetime resources like an HTTP client or database), screen/feature scope (one per screen, destroyed with it — right for per-screen/per-user state), and factory/transient (a fresh instance each time). Getting it wrong causes real bugs: a stateful object made an app-wide singleton leaks its state across users/screens (a new user sees the previous user's data); an expensive shared resource made transient is recreated needlessly, wasting memory and time.", hint: 'Scope is a correctness concern, not just performance.' },
    { id: 'mbfc_arch_14', q: 'How do Android (Hilt) and iOS differ in doing DI?', a: "Android's standard is a compile-time container: Hilt (on Dagger) generates the wiring and verifies the whole graph at build, with predefined components tied to lifecycles (Singleton, Activity/Fragment/ViewModel scope); your classes use constructor injection, framework-created screens use field injection, and a missing/mis-scoped binding fails the build. iOS has no single blessed container — teams use manual constructor injection, lightweight containers (Swinject, Factory), or SwiftUI's environment — trading compile-time graph verification for lighter, more manual control." },
    { id: 'mbfc_arch_15', q: 'Why prefer DI over a Service Locator even though both achieve IoC?', a: "Both invert creation, but with DI the dependencies are pushed in and visible in the constructor signature — you can see exactly what a class needs. A Service Locator has the class pull deps from a global registry, which hides the true dependencies (they vanish from the signature), couples every class to the locator itself, and makes tests fragile because you must populate global state. Hidden dependencies rot a codebase's testability, so DI (especially constructor injection) is preferred and the locator is a last resort.", hint: 'Hidden dependencies are the problem.' },
  ],
  'app-modularization': [
    { id: 'mbfc_arch_16', q: 'What is modularization, the two ways to split a codebase, and why do large teams do it?', a: "Modularization splits a monolith into multiple independently buildable modules with explicit, enforced dependencies. The two axes: layer modules (split by architectural layer — data, domain, UI) and feature modules (split by product feature — checkout, profile, search, each with its own layer slice); large apps combine both, features over shared core/domain/data. Large teams do it to scale code and org: only changed modules rebuild and independent ones build in parallel (faster builds), boundaries become compiler-enforced, illegal dependencies can be forbidden, and separate teams own modules with clear contracts and build features in isolation." },
    { id: 'mbfc_arch_17', q: 'What are the concrete build-time and architectural benefits of modularization?', a: "Build-time: incremental compilation (changing one module recompiles only it and its dependents, not the whole app) and parallelism with caching (independent modules compile simultaneously), so a modularized app builds far faster incrementally than a monolith of the same size. Architectural: real encapsulation (a module exposes a minimal public API and hides internals, so other code physically cannot reach in) and enforced dependencies (each module declares exactly what it depends on, so illegal edges are forbidden and a violation is a build error). Achieved via the build system's module graph, incremental/parallel compilation, and language visibility rules." },
    { id: 'mbfc_arch_18', q: 'What goes wrong with module dependency graphs and what rules keep them healthy?', a: "The graph must be a directed acyclic graph pointing from features down toward shared core/domain/data. Failures: cyclic dependencies (A->B->A) kill parallel builds and encapsulation and signal a mis-drawn boundary; a wrongly directed edge (core/domain depending on a feature, or two features depending directly on each other) reintroduces the tangle and blocks reuse. Healthy rules: keep it acyclic, point dependencies toward shared lower layers, never let features depend on each other directly (decouple via shared abstractions + DI), expose a minimal public API, and let the build system enforce allowed edges so violations fail the build.", hint: 'Keep it acyclic; features never depend on each other.' },
    { id: 'mbfc_arch_19', q: 'How do you decouple two feature modules that need to share something?', a: "Do not add a feature-to-feature edge. Put the contract (an interface) in a small shared module both features depend on — e.g. :core:user with a CurrentUserProvider interface. Each feature depends on that abstraction, not on the other feature; the concrete implementation lives elsewhere and is wired in at runtime via the DI graph at the composition root. Now both features share the abstraction but never depend on each other, so the graph stays acyclic and each feature builds independently." },
    { id: 'mbfc_arch_20', q: 'How do Android and iOS express modularization, and what is the over-modularization trap?', a: "Android uses Gradle modules (:app + :feature:*, :core:*, :data, :domain), each a separate project with an explicit dependencies block, built in parallel and cached; Google recommends the feature-plus-core split, with dynamic feature modules for on-demand delivery. iOS uses Swift Package Manager packages (or framework targets), each with declared dependencies and public/internal access control. The over-modularization trap: splitting into dozens of micro-modules so build configuration, wiring, and cross-module ceremony cost more than they save — so modularize along real product and team seams, not for its own sake.", hint: 'Cut along real seams, not to maximize module count.' },
  ],
}
